// Lab 01: Student Grade Calculator
const item = $input.first().json;

// ดึงข้อมูลจาก body (Webhook อาจส่งมาใน body หรือ root)
const input = item.body || item;

// คำนวณ total (ผลรวมของ scores)
const total = input.scores.reduce((sum, score) => sum + score, 0);

// คำนวณ average (ค่าเฉลี่ย)
const average = Math.round((total / input.scores.length) * 10) / 10;

// ตัดเกรดตามเกณฑ์
let grade;
if (average >= 80) {
  grade = 'A';
} else if (average >= 70) {
  grade = 'B';
} else if (average >= 60) {
  grade = 'C';
} else if (average >= 50) {
  grade = 'D';
} else {
  grade = 'F';
}

// กำหนด status
const status = average >= 50 ? 'passed' : 'failed';

// ส่งผลลัพธ์กลับ
return [{
  json: {
    student_id: input.student_id,
    name: input.name,
    total: total,
    average: average,
    grade: grade,
    status: status
  }
}];
